@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')

    if not all([grant_type, client_id, client_secret]):
        return jsonify({"error": "Missing required parameters"}), 400

    if grant_type != 'authorization_code':
        return jsonify({"error": "Unsupported grant_type"}), 400

    if client_id not in clients:
        return jsonify({"error": "Invalid client_id"}), 401

    client_config = clients[client_id]

    if client_secret != client_config['client_secret']:
        return jsonify({"error": "Invalid client_secret"}), 401

    if redirect_uri != client_config['redirect_uri']:
        return jsonify({"error": "Invalid redirect_uri"}), 400

    if code not in auth_codes:
        return jsonify({"error": "Invalid or expired authorization code"}), 400

    user_id = auth_codes[code]
    # As per requirements, codes can be exchanged multiple times.
    # In a typical OAuth flow, the code would be consumed here.
    # del auth_codes[code] # Not deleting as per requirement

    access_token_value = generate_access_token()
    access_tokens[access_token_value] = {
        'user_id': user_id,
        'client_id': client_id,
        'scope': client_config['scope']
    }
    print(f"Generated access token '{access_token_value}' for user '{user_id}' and client '{client_id}'")

    return jsonify({
        "access_token": access_token_value,
        "token_type": "Bearer",
        # "expires_in": 3600, # Optional: Add expiration for access token
        "scope": client_config['scope']
    })

# --- Resource Server Example (using the token) ---
@app.route('/resource', methods=['GET'])
def resource():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({"error": "Missing or invalid Authorization header"}), 401

    access_token_value = auth_header.split(' ')[1]

    if access_token_value not in access_tokens:
        return jsonify({"error": "Invalid or expired access token"}), 401

    token_info = access_tokens[access_token_value]
    user_id = token_info['user_id']
    client_id = token_info['client_id']
    scope = token_info['scope']

    # In a real application, you'd use the scope to determine what data to return
    # and the user_id to fetch user-specific data.
    return jsonify({
        "message": f"Hello, {user_id}! You accessed a protected resource via client {client_id}.",
        "data": {
            "user_id": user_id,
            "scope": scope,
            "details": "This is sensitive data only available with a valid token."
        }
    })

